lexer grammar SYsULexer;

@lexer::members {
    std::string currentFilename = "<unknown>";
    int currentLine = 1;
    int currentCol = 1;
    bool atStartOfLine = true;
    bool hadLeadingSpace = false;

    class PositionedToken : public antlr4::CommonToken {
    public:
        PositionedToken(size_t type, const std::string &text, const std::string &filename, int line, int col, bool startOfLine, bool leadingSpace)
            : CommonToken(type, text), 
              filename(filename), 
              col(col), 
              startOfLine(startOfLine), 
              leadingSpace(leadingSpace) {}

        std::string filename;
        int col;
        bool startOfLine;
        bool leadingSpace;
    };

    virtual antlr4::Token* emit() override {
        auto token = Lexer::emit();

        // Create our custom token
        auto newToken = new PositionedToken(
            token->getType(), 
            token->getText(),
            currentFilename,
            currentLine,
            currentCol,
            atStartOfLine,
            hadLeadingSpace
        );

        // Delete the original token
        delete token;

        // Update position tracking
        currentCol += newToken->getText().size();
        atStartOfLine = false;
        hadLeadingSpace = false;

        return newToken;
    }
}

